/**
 * Node-RED Function for influxdb batch (InfluxDB 2.0)
 * - Input: msg.payload from MQTT (string JSON or object)
 * - Output: msg.payload = [ {measurement,tags,fields,timestamp}, ... ]
 *
 * Added:
 *  - vpd_kpa (kPa)  [accurate]
 *  - solar_wm2_est (W/m^2) [estimated from lux]
 *  - solar_mj_m2_h_est (MJ/m^2/h) [estimated]
 *  - eto_mm_day_est (mm/day) [rough estimate using FAO-56 structure + estimated radiation]
 *
 * Notes:
 *  - wind_dir_th stays as FIELD (not tag) to avoid high cardinality.
 *  - ETo here is an estimate; for accurate FAO-56 need better radiation/pressure inputs.
 */

// ---------- 1) Parse payload ----------
let p = msg.payload;

if (typeof p === "string") {
    try { p = JSON.parse(p); }
    catch (e) {
        node.warn("Invalid JSON payload (parse failed)");
        return null;
    }
}
if (!p || (!p.env && !p.npk)) return null;

// ---------- 2) Parse time "DD/MM/YYYY HH:MM:SS" -> epoch ms ----------
function parse_ddmmyyyy_hhmmss(s) {
    if (typeof s !== "string") return null;
    const m = s.match(/^(\d{2})\/(\d{2})\/(\d{4})(?:\s+(\d{2}):(\d{2}):(\d{2}))?$/);
    if (!m) return null;

    const dd = Number(m[1]), mm = Number(m[2]), yyyy = Number(m[3]);
    const HH = m[4] !== undefined ? Number(m[4]) : 0;
    const MM = m[5] !== undefined ? Number(m[5]) : 0;
    const SS = m[6] !== undefined ? Number(m[6]) : 0;

    const d = new Date(yyyy, mm - 1, dd, HH, MM, SS);
    return isNaN(d.getTime()) ? null : d.getTime();
}
const ts_ms = parse_ddmmyyyy_hhmmss(p.time) || Date.now();

// ---------- 3) Base tags (constant only) ----------
const base_tags = {
    location: "farm1",
    node: p.node || "unknown_node",
    zone: p.zone || "unknown_zone"
};

// ---------- 4) Helpers ----------
function pick_num_fields(obj, mapping) {
    const out = {};
    for (const [out_key, in_key] of Object.entries(mapping)) {
        const v = obj?.[in_key];
        if (typeof v === "number" && isFinite(v)) out[out_key] = v;
    }
    return out;
}
function pick_int_fields(obj, mapping) {
    const out = {};
    for (const [out_key, in_key] of Object.entries(mapping)) {
        const v = obj?.[in_key];
        if (Number.isInteger(v)) out[out_key] = v;
        else if (typeof v === "number" && isFinite(v)) out[out_key] = Math.round(v);
    }
    return out;
}

// ---------- 5) Calculations ----------
function calc_vpd_kpa(air_temp_c, air_rh_pct) {
    // es = 0.6108 * exp(17.27*T/(T+237.3))
    const es = 0.6108 * Math.exp((17.27 * air_temp_c) / (air_temp_c + 237.3));
    const ea = es * (air_rh_pct / 100.0);
    const vpd = es - ea;
    return { es_kpa: es, ea_kpa: ea, vpd_kpa: vpd };
}

function calc_solar_from_lux(lux) {
    // Rough conversion (daylight): W/m^2 ≈ lux / 120
    // 120 lm/W is an assumption; adjust per your sensor/environment if needed.
    const efficacy_lm_per_w = 120.0;
    const solar_wm2 = lux / efficacy_lm_per_w;
    const solar_mj_m2_h = solar_wm2 * 3600.0 / 1e6; // MJ/m^2 per hour
    return { solar_wm2_est: solar_wm2, solar_mj_m2_h_est: solar_mj_m2_h };
}

function calc_eto_mm_day_est(air_temp_c, vpd_kpa, wind_ms, solar_mj_m2_h_est) {
    // FAO-56 PM structure (estimated inputs)
    // Rn_h ≈ (1 - albedo) * Rs_h ; ignore longwave
    // Then compute ETo_h (mm/h) and scale to mm/day (rough): eto_mm_day_est ≈ eto_h * 24

    const albedo = 0.23;
    const Rn_h = (1.0 - albedo) * solar_mj_m2_h_est; // MJ/m^2/h
    const G = 0.0; // soil heat flux approx

    // slope of saturation vapor pressure curve Δ (kPa/°C)
    const T = air_temp_c;
    const es = 0.6108 * Math.exp((17.27 * T) / (T + 237.3));
    const delta = (4098.0 * es) / Math.pow(T + 237.3, 2);

    // psychrometric constant γ (kPa/°C) ~ 0.0665 at sea level
    // (for better accuracy need pressure or elevation)
    const gamma = 0.0665;

    const u2 = Math.max(0, wind_ms); // assume already at ~2m
    const numerator = (0.408 * delta * (Rn_h - G)) + (gamma * (900.0 / (T + 273.0)) * u2 * vpd_kpa);
    const denom = delta + gamma * (1.0 + 0.34 * u2);

    const eto_mm_h = denom !== 0 ? (numerator / denom) : NaN;
    const eto_mm_day = isFinite(eto_mm_h) ? eto_mm_h * 24.0 : NaN;

    return { eto_mm_h_est: eto_mm_h, eto_mm_day_est: eto_mm_day };
}

// ---------- 6) Build points for influxdb batch ----------
const measurement = "all_sensor_data"; // ตาม flow ของคุณ :contentReference[oaicite:4]{index=4}
let points = [];

// ===== ENV point =====
if (p.env) {
    let fields = {
        ...pick_num_fields(p.env, {
            wind_speed_avg5m: "wind_speed_avg5m",
            wind_dir_deg: "wind_dir_deg",
            lux: "lux",
            air_temp: "Air_temp",
            air_humi: "Air_humi"
        }),
        ...pick_num_fields(p.env, {
            air_temp: "air_temp",
            air_humi: "air_humi"
        })
    };

    // keep wind_dir_th as FIELD
    const wind_dir_th = p.env.wind_dir_th;
    if (typeof wind_dir_th === "string" && wind_dir_th.length) {
        fields.wind_dir_th = wind_dir_th;
    }

    // ---- Derived metrics (only if required inputs exist) ----
    const air_temp = fields.air_temp;
    const air_humi = fields.air_humi;
    const lux = fields.lux;
    const wind_ms = fields.wind_speed_avg5m;

    if (typeof air_temp === "number" && typeof air_humi === "number") {
        const v = calc_vpd_kpa(air_temp, air_humi);
        fields.es_kpa = v.es_kpa;
        fields.ea_kpa = v.ea_kpa;
        fields.vpd_kpa = v.vpd_kpa;

        // solar estimate from lux (if lux exists)
        if (typeof lux === "number") {
            const s = calc_solar_from_lux(lux);
            fields.solar_wm2_est = s.solar_wm2_est;
            fields.solar_mj_m2_h_est = s.solar_mj_m2_h_est;

            // eto estimate (need wind too; if missing assume 0)
            const eto = calc_eto_mm_day_est(air_temp, v.vpd_kpa, (typeof wind_ms === "number" ? wind_ms : 0), s.solar_mj_m2_h_est);
            if (isFinite(eto.eto_mm_h_est)) fields.eto_mm_h_est = eto.eto_mm_h_est;
            if (isFinite(eto.eto_mm_day_est)) fields.eto_mm_day_est = eto.eto_mm_day_est;
        }
    }

    const tags = { ...base_tags, sensor: "env" };

    if (Object.keys(fields).length) {
        points.push({ measurement, tags, fields, timestamp: ts_ms });
    }
}

// ===== NPK point =====
if (p.npk) {
    const fields = {
        ...pick_num_fields(p.npk, {
            soil_temp: "Soil_temp",
            soil_humi: "Soil_humi",
            ec: "ec",
            ph: "ph"
        }),
        ...pick_num_fields(p.npk, {
            soil_temp: "soil_temp",
            soil_humi: "soil_humi"
        }),
        ...pick_int_fields(p.npk, { n: "n", p: "p", k: "k" })
    };

    const tags = { ...base_tags, sensor: "npk" };

    if (Object.keys(fields).length) {
        points.push({ measurement, tags, fields, timestamp: ts_ms });
    }
}

// ---------- 7) Output ----------
if (!points.length) return null;
msg.payload = points;
return msg;

// ===== Parse payload =====
let p = msg.payload;

if (typeof p === "string") {
    try {
        p = JSON.parse(p);
    } catch (e) {
        return null;
    }
}

if (!p || !p.env) return null;

// ===== Extract raw values =====
let air_temp = p.env.air_temp ?? p.env.Air_temp;
let air_humi = p.env.air_humi ?? p.env.Air_humi;
let lux = p.env.lux;
let wind_ms = p.env.wind_speed_avg5m;

// ===== VPD Calculation =====
let vpd_kpa = null;
let es_kpa = null;
let ea_kpa = null;

if (typeof air_temp === "number" && typeof air_humi === "number") {
    es_kpa = 0.6108 * Math.exp((17.27 * air_temp) / (air_temp + 237.3));
    ea_kpa = es_kpa * (air_humi / 100.0);
    vpd_kpa = es_kpa - ea_kpa;
}

// ===== Solar estimate from lux =====
let solar_wm2_est = null;
let solar_mj_m2_h_est = null;

if (typeof lux === "number") {
    const efficacy = 120.0; // lm/W assumption
    solar_wm2_est = lux / efficacy;
    solar_mj_m2_h_est = solar_wm2_est * 3600.0 / 1e6;
}

// ===== ETo estimate =====
let eto_mm_day_est = null;

if (
    typeof air_temp === "number" &&
    typeof vpd_kpa === "number" &&
    typeof solar_mj_m2_h_est === "number"
) {
    const T = air_temp;
    const u2 = typeof wind_ms === "number" ? wind_ms : 0;
    const albedo = 0.23;
    const Rn = (1 - albedo) * solar_mj_m2_h_est;

    const delta =
        (4098 *
            (0.6108 * Math.exp((17.27 * T) / (T + 237.3)))) /
        Math.pow(T + 237.3, 2);

    const gamma = 0.0665;

    const numerator =
        0.408 * delta * Rn +
        gamma * (900 / (T + 273)) * u2 * vpd_kpa;

    const denominator =
        delta + gamma * (1 + 0.34 * u2);

    const eto_mm_h =
        denominator !== 0 ? numerator / denominator : null;

    if (eto_mm_h !== null && isFinite(eto_mm_h)) {
        eto_mm_day_est = eto_mm_h * 24;
    }
}

// ===== Build telemetry payload =====
let telemetry = {
    air_temp: air_temp,
    air_humi: air_humi,
    wind_speed_avg5m: wind_ms,
    wind_dir_deg: p.env.wind_dir_deg,
    lux: lux,
    soil_temp: p.npk?.soil_temp ?? p.npk?.Soil_temp,
    soil_humi: p.npk?.soil_humi ?? p.npk?.Soil_humi,
    ec: p.npk?.ec,
    ph: p.npk?.ph,
    n: p.npk?.n,
    p: p.npk?.p,
    k: p.npk?.k,
    vpd_kpa: vpd_kpa,
    solar_wm2_est: solar_wm2_est,
    solar_mj_m2_h_est: solar_mj_m2_h_est,
    eto_mm_day_est: eto_mm_day_est
};

// ===== Send to ThingsBoard =====
msg.payload = telemetry;
return msg;
